App.Pages.CustomerDashboard=function(){const e="DMY"===vars("date_format")?"DD/MM/YYYY":"MDY"===vars("date_format")?"MM/DD/YYYY":"YYYY/MM/DD",a="regular"===vars("time_format")?"h:mm A":"HH:mm";function t(t,n){const s=moment(t.start_datetime),i=moment(t.end_datetime),c="Cancelled"===t.status,l=App.Utils.Url.siteUrl("booking/reschedule/"+t.hash);let m="";c?m='<span class="badge bg-danger">'+lang("cancelled")+"</span>":t.status&&(m='<span class="badge bg-secondary">'+App.Utils.String.escapeHtml(t.status)+"</span>");let r="";if(c){const n=t.cancelled_by||"";if(r='<div class="mt-2 small text-danger">',r+='<i class="fas fa-ban me-1"></i>'+(-1!==n.indexOf("(customer)")?lang("cancelled_by_me"):lang("cancelled_by")+" "+App.Utils.String.escapeHtml(n.replace(/\s*\((admin|provider|secretary|customer)\)/,""))),t.cancelled_at){r+=" &middot; "+moment(t.cancelled_at).format(e+" "+a)}t.cancellation_reason&&(r+='<br><i class="fas fa-comment me-1"></i>'+App.Utils.String.escapeHtml(t.cancellation_reason)),r+="</div>"}return`\n            <div class="card mb-3 ${c?"border-danger bg-light":""}">\n                <div class="card-body">\n                    <div class="d-flex justify-content-between align-items-start">\n                        <div>\n                            <h6 class="card-title mb-1">\n                                <i class="fas fa-concierge-bell me-1 text-primary"></i>\n                                ${c?App.Utils.String.escapeHtml(t.service_name||""):'<a href="'+l+'" class="text-decoration-none">'+App.Utils.String.escapeHtml(t.service_name||"")+"</a>"}\n                            </h6>\n                            <p class="card-text text-muted small mb-1">\n                                <i class="fas fa-user-md me-1"></i>\n                                ${App.Utils.String.escapeHtml(t.provider_name||"")}\n                            </p>\n                            <p class="card-text small mb-0">\n                                <i class="fas fa-calendar-day me-1"></i>\n                                ${s.format(e)}\n                                &nbsp;\n                                <i class="fas fa-clock me-1"></i>\n                                ${s.format(a)} - ${i.format(a)}\n                            </p>\n                            ${r}\n                        </div>\n                        <div>\n                            ${m}\n                        </div>\n                    </div>\n                </div>\n            </div>\n        `}return document.addEventListener("DOMContentLoaded",function(){App.Http.Customer.getAppointments().done(e=>{$("#upcoming-loading, #past-loading").hide(),e.upcoming&&e.upcoming.length?($("#upcoming-count").text(e.upcoming.length).show(),e.upcoming.forEach(e=>{$("#upcoming-list").append(t(e))})):$("#upcoming-empty").show(),e.past&&e.past.length?e.past.forEach(e=>{$("#past-list").append(t(e))}):$("#past-empty").show()})}),{}}();